import{_ as i,o as l,c as e,ae as s}from"./chunks/framework.jfJLTIcL.js";const u=JSON.parse('{"title":"从私有源码仓到公开发布仓：VILab 的桌面应用发布架构实践","description":"","frontmatter":{},"headers":[],"relativePath":"zh-CN/public-release-architecture.md","filePath":"zh-CN/public-release-architecture.md","lastUpdated":1775407660000}'),t={name:"zh-CN/public-release-architecture.md"};function o(p,a,h,d,n,c){return l(),e("div",null,[...a[0]||(a[0]=[s('<h1 id="从私有源码仓到公开发布仓-vilab-的桌面应用发布架构实践" tabindex="-1">从私有源码仓到公开发布仓：VILab 的桌面应用发布架构实践 <a class="header-anchor" href="#从私有源码仓到公开发布仓-vilab-的桌面应用发布架构实践" aria-label="Permalink to &quot;从私有源码仓到公开发布仓：VILab 的桌面应用发布架构实践&quot;">​</a></h1><p>这篇文章记录的是 VILab 桌面应用从“私有源码仓直接开发”演进到“私有源码仓 + 公开发布仓 + GitHub Pages 自定义域名”的完整实践。</p><p>它不是一篇抽象讨论，而是一套已经落地的发布架构说明，覆盖了：</p><ul><li>为什么要拆分私有开发仓和公开发布仓</li><li>如何设计公开站点、下载页、更新日志与文档入口</li><li>如何让 Tauri 桌面应用切换到公开更新源</li><li>如何把 GitHub Pages 和自定义域名 <code>vilab.orulink.ai</code> 接起来</li><li>实际落地时会遇到哪些问题，以及如何判断是否真的成功</li></ul><h2 id="为什么要做这次改造" tabindex="-1">为什么要做这次改造 <a class="header-anchor" href="#为什么要做这次改造" aria-label="Permalink to &quot;为什么要做这次改造&quot;">​</a></h2><p>项目早期，源码仓库是私有的，这对研发协作没有问题，但对桌面应用的正式分发并不友好。</p><p>最主要的矛盾点有四个：</p><ol><li>私有仓库不适合作为最终用户的自动更新源。</li><li>用户需要一个公开可访问的下载入口。</li><li>每次发版最好有公开可查的版本说明和更新日志。</li><li>文档、下载、更新说明最好统一收口到一个正式域名下。</li></ol><p>如果继续让客户端直接追私有仓库 release，会带来一系列现实问题：</p><ul><li>GitHub 私有 release 资产不适合匿名访问</li><li>客户端内置 updater 不应该依赖用户额外登录 GitHub</li><li>自动更新链路会被权限和 token 管理复杂化</li><li>用户无法自然获取下载、文档和 changelog</li></ul><p>所以更合理的做法是把职责拆开：</p><ul><li>私有仓库继续负责开发与构建控制</li><li>公开仓库专门负责对外分发</li></ul><p>这就是这次改造的出发点。</p><h2 id="最终采用的架构" tabindex="-1">最终采用的架构 <a class="header-anchor" href="#最终采用的架构" aria-label="Permalink to &quot;最终采用的架构&quot;">​</a></h2><p>这次最终落地的结构是三层：</p><h3 id="_1-私有源码仓" tabindex="-1">1. 私有源码仓 <a class="header-anchor" href="#_1-私有源码仓" aria-label="Permalink to &quot;1. 私有源码仓&quot;">​</a></h3><p>私有仓仍然是唯一的开发主仓，负责：</p><ul><li>源码</li><li>workflow</li><li>构建脚本</li><li>版本说明源文件</li><li>发布控制逻辑</li></ul><p>也就是说，所有内容仍然从私有仓生产出来。</p><h3 id="_2-公开发布仓" tabindex="-1">2. 公开发布仓 <a class="header-anchor" href="#_2-公开发布仓" aria-label="Permalink to &quot;2. 公开发布仓&quot;">​</a></h3><p>新增公开仓：</p><ul><li><code>Ro-In-AI/VILab-public</code></li></ul><p>它只负责公开分发，不承担主开发职责。主要承载：</p><ul><li>GitHub Releases</li><li>安装包</li><li>签名文件</li><li>checksum</li><li><code>latest.json</code></li><li>静态官网</li><li>下载页</li><li>更新日志页</li><li>公共文档</li></ul><h3 id="_3-自定义域名" tabindex="-1">3. 自定义域名 <a class="header-anchor" href="#_3-自定义域名" aria-label="Permalink to &quot;3. 自定义域名&quot;">​</a></h3><p>最终对外使用的域名是：</p><ul><li><code>vilab.orulink.ai</code></li></ul><p>公开站点内容统一从这个域名提供：</p><ul><li><code>/</code>：官网首页</li><li><code>/docs/</code>：文档</li><li><code>/download/</code>：下载页</li><li><code>/changelog/</code>：更新日志</li></ul><h2 id="为什么是-公开发布仓-而不是-公开源码仓" tabindex="-1">为什么是“公开发布仓”，而不是“公开源码仓” <a class="header-anchor" href="#为什么是-公开发布仓-而不是-公开源码仓" aria-label="Permalink to &quot;为什么是“公开发布仓”，而不是“公开源码仓”&quot;">​</a></h2><p>这是这次设计里非常重要的一个原则。</p><p>很多项目在这个阶段会纠结“要不要直接把源码开源”。但这其实是另一个问题。</p><p>这里要解决的是“如何把产品正确发布给用户”，而不是“是否公开开发过程”。</p><p>所以 VILab 采用的是：</p><ul><li>私有开发</li><li>公开分发</li></ul><p>这样做的好处很明确：</p><ul><li>研发流程保持私有和稳定</li><li>自动更新源可以匿名访问</li><li>用户能直接看到 release、下载和 changelog</li><li>文档和产品入口可以统一到正式域名</li><li>不必为了分发而暴露源码历史</li></ul><p>这套模式非常适合桌面应用，尤其适合：</p><ul><li>Tauri 项目</li><li>Electron 项目</li><li>商业化早期产品</li><li>仍处于私有迭代阶段的工具型软件</li></ul><h2 id="站点结构如何设计" tabindex="-1">站点结构如何设计 <a class="header-anchor" href="#站点结构如何设计" aria-label="Permalink to &quot;站点结构如何设计&quot;">​</a></h2><p>这次没有额外起一个新的官网工程，而是直接基于现有文档体系扩展。</p><p>项目原本已经有 VitePress 文档，因此公开站点被设计成两层：</p><h3 id="第一层-公开入口页" tabindex="-1">第一层：公开入口页 <a class="header-anchor" href="#第一层-公开入口页" aria-label="Permalink to &quot;第一层：公开入口页&quot;">​</a></h3><p>由自定义脚本生成：</p><ul><li><code>/</code></li><li><code>/download/</code></li><li><code>/changelog/</code></li></ul><p>这层负责面向用户的公开入口和版本说明。</p><h3 id="第二层-文档页" tabindex="-1">第二层：文档页 <a class="header-anchor" href="#第二层-文档页" aria-label="Permalink to &quot;第二层：文档页&quot;">​</a></h3><p>继续使用 VitePress：</p><ul><li><code>/docs/</code></li></ul><p>这样做的最大收益是：</p><ul><li>不需要维护第二套前端栈</li><li>本地内嵌文档路径仍然保持稳定</li><li>公共站点和文档自然整合</li><li>静态构建链路足够简单</li></ul><h2 id="关键实现改造" tabindex="-1">关键实现改造 <a class="header-anchor" href="#关键实现改造" aria-label="Permalink to &quot;关键实现改造&quot;">​</a></h2><h2 id="一、生成完整的公开站点产物" tabindex="-1">一、生成完整的公开站点产物 <a class="header-anchor" href="#一、生成完整的公开站点产物" aria-label="Permalink to &quot;一、生成完整的公开站点产物&quot;">​</a></h2><p>为了让公开仓不只是一个 release 仓，而是真正的“公开入口”，新增了脚本：</p><ul><li><code>scripts/build-public-site.mjs</code></li></ul><p>它负责把以下内容组装成一个完整的静态站：</p><ul><li>官网首页</li><li>下载页</li><li>changelog 列表页</li><li>每个版本的 changelog 详情页</li><li>VitePress 文档构建产物</li></ul><p>这个脚本会读取：</p><ul><li><code>.github/releases/*.md</code></li></ul><p>然后自动生成 changelog 页面，同时把 <code>docs/.vitepress/dist</code> 复制到最终产物里的 <code>/docs/</code> 下。</p><p>最终输出目录是：</p><ul><li><code>public-site/dist</code></li></ul><p>这样，公开仓得到的就不再是零散的 release 资产，而是一个完整可部署的公开站。</p><h2 id="二、把公开站点同步到公开仓" tabindex="-1">二、把公开站点同步到公开仓 <a class="header-anchor" href="#二、把公开站点同步到公开仓" aria-label="Permalink to &quot;二、把公开站点同步到公开仓&quot;">​</a></h2><p>新增了同步脚本：</p><ul><li><code>scripts/sync-public-repo.mjs</code></li></ul><p>它的职责是：</p><ul><li>克隆公开仓</li><li>切到 <code>main</code></li><li>清理旧站点内容</li><li>把 <code>public-site/dist</code> 整体复制进去</li><li>自动提交并推送</li></ul><p>这样一来，公共站点的同步动作就被标准化成了两步：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> public:site:build</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> public:repo:sync</span></span></code></pre></div><p>这让“更新官网”和“发布版本”可以共享同一套控制逻辑。</p><h2 id="三、把桌面-updater-切到公开仓" tabindex="-1">三、把桌面 updater 切到公开仓 <a class="header-anchor" href="#三、把桌面-updater-切到公开仓" aria-label="Permalink to &quot;三、把桌面 updater 切到公开仓&quot;">​</a></h2><p>原本 updater 指向旧仓库 release，现在已经切到公开仓。</p><p>Tauri 配置中的 updater endpoint 改成：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://github.com/Ro-In-AI/VILab-public/releases/latest/download/latest.json</span></span></code></pre></div><p>这意味着后续客户端正式更新只认公开发布仓，不再依赖私有仓。</p><p>对应修改点在：</p><ul><li><code>src-tauri/tauri.conf.json</code></li></ul><p>同时，<code>latest.json</code> 的生成脚本也改成了支持目标仓参数：</p><ul><li><code>PUBLIC_RELEASE_REPO</code></li></ul><p>对应脚本：</p><ul><li><code>scripts/generate-updater-manifest.mjs</code></li></ul><h2 id="四、让应用内文档入口自动跳到公开域名" tabindex="-1">四、让应用内文档入口自动跳到公开域名 <a class="header-anchor" href="#四、让应用内文档入口自动跳到公开域名" aria-label="Permalink to &quot;四、让应用内文档入口自动跳到公开域名&quot;">​</a></h2><p>应用内原本就有文档入口，但之前只有简单的 fallback URL。</p><p>这次把文档地址优先级改成了：</p><ol><li><code>VITE_DOCS_URL</code></li><li><code>VITE_PUBLIC_SITE_URL + /docs/</code></li><li>默认 fallback</li></ol><p>这样发布时只要设置：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">VITE_PUBLIC_SITE_URL</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">https://vilab.orulink.ai</span></span></code></pre></div><p>应用里的文档入口就会自动跳到：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://vilab.orulink.ai/docs/</span></span></code></pre></div><p>对应文件：</p><ul><li><code>src/lib/docs.ts</code></li></ul><h2 id="五、把-workflow-改成跨仓发布" tabindex="-1">五、把 workflow 改成跨仓发布 <a class="header-anchor" href="#五、把-workflow-改成跨仓发布" aria-label="Permalink to &quot;五、把 workflow 改成跨仓发布&quot;">​</a></h2><p>为了让私有仓成为真正的“发布控制面”，workflow 也一起调整了。</p><p>新增或调整后的主要 workflow 包括：</p><ul><li><code>.github/workflows/docs.yml</code></li><li><code>.github/workflows/release-windows.yml</code></li><li><code>.github/workflows/release-mac.yml</code></li></ul><p>它们的目标是：</p><ul><li>Windows 版本发到公开仓 release</li><li>macOS 版本发到公开仓 release</li><li>公共站点内容同步到公开仓 <code>main</code></li></ul><p>这样，私有仓仍然是控制中心，而公开仓只是分发终点。</p><h2 id="核心环境变量和-secrets" tabindex="-1">核心环境变量和 Secrets <a class="header-anchor" href="#核心环境变量和-secrets" aria-label="Permalink to &quot;核心环境变量和 Secrets&quot;">​</a></h2><p>这套架构中最关键的三个变量是：</p><h3 id="_1-public-release-repo" tabindex="-1">1. <code>PUBLIC_RELEASE_REPO</code> <a class="header-anchor" href="#_1-public-release-repo" aria-label="Permalink to &quot;1. `PUBLIC_RELEASE_REPO`&quot;">​</a></h3><p>例如：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Ro-In-AI/VILab-public</span></span></code></pre></div><p>它告诉脚本：最终应该把内容发布到哪个公开仓。</p><h3 id="_2-public-release-pat" tabindex="-1">2. <code>PUBLIC_RELEASE_PAT</code> <a class="header-anchor" href="#_2-public-release-pat" aria-label="Permalink to &quot;2. `PUBLIC_RELEASE_PAT`&quot;">​</a></h3><p>这是一个 GitHub token，用来让私有仓 workflow 或本地终端获得写公开仓的权限。</p><p>它主要用于：</p><ul><li>推送公开站点</li><li>创建和更新公开 release</li><li>上传安装包、签名文件和 <code>latest.json</code></li></ul><h3 id="_3-public-site-domain" tabindex="-1">3. <code>PUBLIC_SITE_DOMAIN</code> <a class="header-anchor" href="#_3-public-site-domain" aria-label="Permalink to &quot;3. `PUBLIC_SITE_DOMAIN`&quot;">​</a></h3><p>例如：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>vilab.orulink.ai</span></span></code></pre></div><p>它的作用是：</p><ul><li>生成 <code>CNAME</code></li><li>生成公开站点 canonical URL</li><li>让文档、下载和 changelog 链接统一指向正式域名</li></ul><h2 id="域名为什么选择-vilab-orulink-ai" tabindex="-1">域名为什么选择 <code>vilab.orulink.ai</code> <a class="header-anchor" href="#域名为什么选择-vilab-orulink-ai" aria-label="Permalink to &quot;域名为什么选择 `vilab.orulink.ai`&quot;">​</a></h2><p>这次没有直接使用根域名 <code>orulink.ai</code>，而是选择了子域名：</p><ul><li><code>vilab.orulink.ai</code></li></ul><p>原因很简单：</p><ul><li>子域名接 GitHub Pages 更简单</li><li>DNS 配置更清晰</li><li>不需要根域名的 <code>A/AAAA</code> 复杂配置</li><li>后续主域名还可以留给官网、导航页或其他产品</li></ul><p>对于 GitHub Pages 来说，子域名通常是更稳妥的选择。</p><h2 id="dns-是怎么配置的" tabindex="-1">DNS 是怎么配置的 <a class="header-anchor" href="#dns-是怎么配置的" aria-label="Permalink to &quot;DNS 是怎么配置的&quot;">​</a></h2><p>因为是子域名，所以最终只需要一条 <code>CNAME</code>：</p><ul><li>类型：<code>CNAME</code></li><li>主机记录：<code>vilab</code></li><li>记录值：<code>ro-in-ai.github.io</code></li></ul><p>注意几个容易踩坑的点：</p><ul><li>不要写成 <code>ro-in-ai.github.io/VILab-public</code></li><li>不要把 <code>vilab.orulink.ai</code> 先跳去 <code>orulink.ai</code></li><li>不要配通配符 <code>*</code></li></ul><p>正确的做法就是让 <code>vilab.orulink.ai</code> 直接 <code>CNAME</code> 到 <code>ro-in-ai.github.io</code></p><h2 id="我是如何验证-dns-成功的" tabindex="-1">我是如何验证 DNS 成功的 <a class="header-anchor" href="#我是如何验证-dns-成功的" aria-label="Permalink to &quot;我是如何验证 DNS 成功的&quot;">​</a></h2><p>最直接的方法是用 <code>dig</code>：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dig</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> vilab.orulink.ai</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> CNAME</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> +short</span></span></code></pre></div><p>当返回：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ro-in-ai.github.io.</span></span></code></pre></div><p>就说明 DNS 方向已经正确。</p><p>在这次实际测试里，确实得到了这个结果，所以 DNS 本身没有问题。</p><h2 id="为什么一开始-https-还是不通" tabindex="-1">为什么一开始 HTTPS 还是不通 <a class="header-anchor" href="#为什么一开始-https-还是不通" aria-label="Permalink to &quot;为什么一开始 HTTPS 还是不通&quot;">​</a></h2><p>这是这次最容易让人误解的地方。</p><p>GitHub Pages 后台显示的是：</p><ul><li><code>DNS check successful</code></li><li><code>Enforce HTTPS — Unavailable ... because a certificate has not yet been issued</code></li></ul><p>这个状态说明：</p><ul><li>DNS 已正确</li><li>GitHub Pages 已识别域名绑定</li><li>站点内容已经能提供</li><li>唯一还没完成的是 TLS 证书签发</li></ul><p>也就是说，这时候如果 HTTPS 报错，并不代表配置失败。</p><p>实际测试时我得到的现象是：</p><h3 id="http-已经正常" tabindex="-1">HTTP 已经正常 <a class="header-anchor" href="#http-已经正常" aria-label="Permalink to &quot;HTTP 已经正常&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -I</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://vilab.orulink.ai</span></span></code></pre></div><p>返回 <code>200 OK</code></p><h3 id="https-证书还未就绪" tabindex="-1">HTTPS 证书还未就绪 <a class="header-anchor" href="#https-证书还未就绪" aria-label="Permalink to &quot;HTTPS 证书还未就绪&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -I</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://vilab.orulink.ai</span></span></code></pre></div><p>会报证书不匹配</p><p>进一步查看证书：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openssl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> s_client</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -connect</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> vilab.orulink.ai:443</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -servername</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> vilab.orulink.ai</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/dev/null</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> 2&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/dev/null</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> openssl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> x509</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -noout</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -subject</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -issuer</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -ext</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> subjectAltName</span></span></code></pre></div><p>看到的还是 GitHub 默认的：</p><ul><li><code>CN=*.github.io</code></li></ul><p>这意味着：</p><ul><li>Pages 的内容已经在</li><li>域名绑定已经在</li><li>但针对 <code>vilab.orulink.ai</code> 的专属证书还没发下来</li></ul><p>这一步通常只能等待 GitHub Pages 自动完成。</p><h2 id="如何判断-https-真正生效了" tabindex="-1">如何判断 HTTPS 真正生效了 <a class="header-anchor" href="#如何判断-https-真正生效了" aria-label="Permalink to &quot;如何判断 HTTPS 真正生效了&quot;">​</a></h2><p>当以下两个信号出现时，就说明 HTTPS 已经真正完成：</p><h3 id="_1-github-pages-后台" tabindex="-1">1. GitHub Pages 后台 <a class="header-anchor" href="#_1-github-pages-后台" aria-label="Permalink to &quot;1. GitHub Pages 后台&quot;">​</a></h3><p><code>Enforce HTTPS</code> 从灰色不可选变成可勾选</p><h3 id="_2-终端校验通过" tabindex="-1">2. 终端校验通过 <a class="header-anchor" href="#_2-终端校验通过" aria-label="Permalink to &quot;2. 终端校验通过&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -I</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://vilab.orulink.ai</span></span></code></pre></div><p>不再报证书错误</p><p>同时，<code>openssl</code> 查看证书时，<code>subjectAltName</code> 中会出现：</p><ul><li><code>vilab.orulink.ai</code></li></ul><p>这时就可以认为整个域名接入彻底完成。</p><h2 id="这次改造的收益" tabindex="-1">这次改造的收益 <a class="header-anchor" href="#这次改造的收益" aria-label="Permalink to &quot;这次改造的收益&quot;">​</a></h2><p>当整个链路打通后，收益是非常直接的。</p><h3 id="_1-私有开发与公开分发彻底解耦" tabindex="-1">1. 私有开发与公开分发彻底解耦 <a class="header-anchor" href="#_1-私有开发与公开分发彻底解耦" aria-label="Permalink to &quot;1. 私有开发与公开分发彻底解耦&quot;">​</a></h3><p>开发过程继续保持私有，不影响产品对外发布。</p><h3 id="_2-自动更新真正面向最终用户" tabindex="-1">2. 自动更新真正面向最终用户 <a class="header-anchor" href="#_2-自动更新真正面向最终用户" aria-label="Permalink to &quot;2. 自动更新真正面向最终用户&quot;">​</a></h3><p>客户端现在可以直接从公开仓读取 <code>latest.json</code>，不再依赖私有访问权限。</p><h3 id="_3-官网、下载、文档和-changelog-收口到一个域名" tabindex="-1">3. 官网、下载、文档和 changelog 收口到一个域名 <a class="header-anchor" href="#_3-官网、下载、文档和-changelog-收口到一个域名" aria-label="Permalink to &quot;3. 官网、下载、文档和 changelog 收口到一个域名&quot;">​</a></h3><p>用户只要记住：</p><ul><li><code>vilab.orulink.ai</code></li></ul><p>就能找到全部公开内容。</p><h3 id="_4-release-notes-不再只是内部-markdown" tabindex="-1">4. Release notes 不再只是内部 markdown <a class="header-anchor" href="#_4-release-notes-不再只是内部-markdown" aria-label="Permalink to &quot;4. Release notes 不再只是内部 markdown&quot;">​</a></h3><p>每个版本说明不只是私有仓里的记录，而是真正成为了公开 changelog 页面的一部分。</p><h2 id="过程中最重要的经验" tabindex="-1">过程中最重要的经验 <a class="header-anchor" href="#过程中最重要的经验" aria-label="Permalink to &quot;过程中最重要的经验&quot;">​</a></h2><h3 id="_1-自动更新源必须从最终用户视角设计" tabindex="-1">1. 自动更新源必须从最终用户视角设计 <a class="header-anchor" href="#_1-自动更新源必须从最终用户视角设计" aria-label="Permalink to &quot;1. 自动更新源必须从最终用户视角设计&quot;">​</a></h3><p>不要只看开发者方便不方便，要看普通用户是否能够匿名访问和顺利更新。</p><h3 id="_2-公开发布仓不等于公开源码仓" tabindex="-1">2. 公开发布仓不等于公开源码仓 <a class="header-anchor" href="#_2-公开发布仓不等于公开源码仓" aria-label="Permalink to &quot;2. 公开发布仓不等于公开源码仓&quot;">​</a></h3><p>公开分发和开源开发是两件事，不应该混为一谈。</p><h3 id="_3-github-pages-接子域名明显比接根域名轻松" tabindex="-1">3. GitHub Pages 接子域名明显比接根域名轻松 <a class="header-anchor" href="#_3-github-pages-接子域名明显比接根域名轻松" aria-label="Permalink to &quot;3. GitHub Pages 接子域名明显比接根域名轻松&quot;">​</a></h3><p><code>vilab.orulink.ai</code> 这种方式比直接用 <code>orulink.ai</code> 更稳更省心。</p><h3 id="_4-dns-配对成功不等于-https-已经完成" tabindex="-1">4. DNS 配对成功不等于 HTTPS 已经完成 <a class="header-anchor" href="#_4-dns-配对成功不等于-https-已经完成" aria-label="Permalink to &quot;4. DNS 配对成功不等于 HTTPS 已经完成&quot;">​</a></h3><p>很多时候 DNS 是对的，但证书还在签发中，这属于正常中间态。</p><h3 id="_5-先让公开仓内容跑通-再接正式域名" tabindex="-1">5. 先让公开仓内容跑通，再接正式域名 <a class="header-anchor" href="#_5-先让公开仓内容跑通-再接正式域名" aria-label="Permalink to &quot;5. 先让公开仓内容跑通，再接正式域名&quot;">​</a></h3><p>只有在公开仓内容和 Pages 部署已经成功时，域名接入才真正有意义。</p><h2 id="最终结论" tabindex="-1">最终结论 <a class="header-anchor" href="#最终结论" aria-label="Permalink to &quot;最终结论&quot;">​</a></h2><p>这次实践最后得到的是一套比较完整且可复用的发布架构：</p><ul><li>私有源码仓继续承担开发职责</li><li>公开仓 <code>Ro-In-AI/VILab-public</code> 负责分发</li><li>GitHub Releases 提供安装包、签名、校验和更新清单</li><li>GitHub Pages 提供官网、文档、下载和 changelog</li><li>自定义域名 <code>vilab.orulink.ai</code> 统一对外</li><li>桌面应用 updater 指向公开仓</li></ul><p>这套方案的意义不只是“把站点搭起来”，而是把整个项目从“能开发”推进到了“能正式交付”。</p><p>对于任何一个桌面应用来说，源码只是产品的一部分。<br> 真正的发布链路、更新链路、文档入口和公开分发面，本身也是产品能力的一部分。</p><p>而公开发布仓，恰恰就是把这些能力组织起来的关键节点。</p>',193)])])}const b=i(t,[["render",o]]);export{u as __pageData,b as default};
